import uuid

def run_conversation(messages: list, session_id: str | None = None) -> str:
    if session_id is None:
        session_id = str(uuid.uuid4())   # stable for this conversation

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        messages=messages,
        extra_headers={
            "Helicone-Session-Id": session_id,
            "Helicone-Session-Path": f"/turn-{len(messages)}",
            "Helicone-Session-Name": "support-conversation",
        },
    )
    return response.content[0].text, session_id

