import requests as http_requests

def log_user_feedback(helicone_id: str, positive: bool) -> None:
    """Submit thumbs-up (True) or thumbs-down (False) for a logged request."""
    resp = http_requests.post(
        "https://api.helicone.ai/v1/feedback",
        headers={
            "Helicone-Auth": f"Bearer {os.environ['HELICONE_API_KEY']}",
            "Content-Type": "application/json",
        },
        json={
            "helicone-id": helicone_id,
            "rating": positive,   # True = positive, False = negative
        },
    )
    resp.raise_for_status()

def call_and_get_id(message: str):
    # Use the raw httpx transport to read the Helicone-Id response header
    import httpx
    raw = httpx.post(
        "https://anthropic.helicone.ai/v1/messages",
        headers={
            "x-api-key": os.environ["ANTHROPIC_API_KEY"],
            "anthropic-version": "2023-06-01",
            "Helicone-Auth": f"Bearer {os.environ['HELICONE_API_KEY']}",
            "Content-Type": "application/json",
        },
        json={
            "model": "claude-haiku-4-5-20251001",
            "max_tokens": 512,
            "messages": [{"role": "user", "content": message}],
        },
    )
    helicone_id = raw.headers.get("helicone-id")
    answer = raw.json()["content"][0]["text"]
    return answer, helicone_id

answer, hid = call_and_get_id("What is Helicone?")
