import requests as http
from datetime import datetime, timedelta, timezone

HELICONE_API_KEY = os.environ["HELICONE_API_KEY"]

def fetch_recent_requests(
    feature: str = "support-agent",
    hours: int = 24,
) -> list[dict]:
    """Return logged requests for a given feature in the past N hours."""
    cutoff = datetime.now(timezone.utc) - timedelta(hours=hours)
    response = http.post(
        "https://api.helicone.ai/v1/request/query",
        headers={
            "Helicone-Auth": f"Bearer {HELICONE_API_KEY}",
            "Content-Type": "application/json",
        },
        json={
            "filter": {
                "request": {
                    "properties": {"Feature": {"equals": feature}},
                    "created_at": {"gte": cutoff.isoformat()},
                }
            },
            "limit": 100,
            "sort": {"created_at": "desc"},
        },
    )
    response.raise_for_status()
    return response.json()["data"]

requests_data = fetch_recent_requests()
for req in requests_data[:5]:
    print(
        req["request"]["model"],
        req["response"]["completion_tokens"],
        req["latency"],  # milliseconds
    )

